#[tokio::test]
async fn test_transfer_hook_rejects_unknown_program() {
    // Mint with TransferHook pointing to attacker-controlled program
    let malicious_mint = setup_mint_with_transfer_hook(&malicious_program.pubkey());
    let exploit_tx = Transaction::new_signed_with_payer(
        &[hook_withdraw_ix(&program_id, &malicious_mint, amount)],
        Some(&user.pubkey()),
        &[&user],
        recent_blockhash,
    );
    let result = program.rpc().process_transaction(&exploit_tx).await;
    assert!(result.is_err());  // Must reject unknown hook_program_id
}
